using System.ComponentModel;
using System.Drawing.Design;
using System.Windows.Forms;
using System.Windows.Forms.Design;

public class MyControl : UserControl
{
    public string DisplayName { get; set; }
    public int MaxItems { get; set; }

    private readonly StatusStrip _statusStrip;

    public MyControl()
    {
        _statusStrip = new StatusStrip();
        // .NET 9 breaking change: default renderer changed from Professional to System.
        // Explicitly set Professional to preserve .NET 8 visual appearance.
        _statusStrip.RenderMode = ToolStripRenderMode.Professional;
        Controls.Add(_statusStrip);
    }
}

public class MyEditor : UITypeEditor
{
    public override object EditValue(ITypeDescriptorContext context,
        IServiceProvider provider, object value)
    {
        var editorService = provider?.GetService(typeof(IWindowsFormsEditorService))
            as IWindowsFormsEditorService;

        if (editorService != null)
        {
            var control = CreateDropDownControl(value);
            // .NET 9 breaking change: DropDownControl(null) now throws
            // ArgumentNullException. Guard against null before calling.
            if (control != null)
            {
                editorService.DropDownControl(control);
                value = control.Tag ?? value;
            }
        }

        return value;
    }

    private Control CreateDropDownControl(object value)
    {
        if (value == null) return null;
        var listBox = new ListBox();
        listBox.Tag = value;
        return listBox;
    }
}

